import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext"; // ✅ add this
import { loginAdmin } from "../services/api";
import { Container, Paper, Typography, TextField, Button, Alert } from "@mui/material";

export default function AdminLogin() {
  const [form, setForm] = useState({ username: "", password: "" });
  const [error, setError] = useState("");
  const navigate = useNavigate();
  const { login } = useAuth(); // ✅ use context login

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    try {
      // For static login, you can skip API call if desired
      if (form.username === "admin" && form.password === "admin123") {
        const authData = { token: "staticadmintoken", role: "admin" };
        login(authData); // ✅ update context AND localStorage
        navigate("/admin-dashboard"); // ✅ navigate immediately
        return;
      }

      // Optional: call backend if you want dynamic login
      // const res = await loginAdmin(form);
      // if (res.data.success) {
      //   login({ token: res.data.token, role: "admin" });
      //   navigate("/admin-dashboard");
      // } else {
      //   setError(res.data.message || "Login failed");
      // }

      setError("Login failed. Check credentials.");
    } catch (err) {
      setError(err.response?.data?.message || "Login failed");
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper elevation={3} sx={{ p: 4, mt: 10 }}>
        <Typography variant="h5" textAlign="center" fontWeight="bold" gutterBottom>
          Admin Login
        </Typography>

        <form onSubmit={handleSubmit}>
          <TextField
            fullWidth
            margin="normal"
            label="Username"
            name="username"
            value={form.username}
            onChange={handleChange}
            required
          />
          <TextField
            fullWidth
            margin="normal"
            label="Password"
            name="password"
            type="password"
            value={form.password}
            onChange={handleChange}
            required
          />

          {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}

          <Button type="submit" variant="contained" fullWidth sx={{ mt: 3 }}>
            Login
          </Button>
        </form>
      </Paper>
    </Container>
  );
}
